@* Vertical tab navigation for settings sections *@

<nav class="settings-sidebar">
    <h5 class="px-3 py-2 text-muted text-uppercase fw-semibold small">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link w-100 text-start @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="me-2">@GetIcon(section)</span>@section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-sidebar {
    min-width: 220px;
    border-right: 1px solid var(--bs-border-color);
    padding: 1rem 0;
    background: var(--bs-tertiary-bg);
    height: 100%;
}

.settings-sidebar .nav-link {
    color: var(--bs-body-color);
    padding: 0.6rem 1.25rem;
    border-radius: 0;
    border-left: 3px solid transparent;
    font-size: 0.95rem;
    transition: all 0.15s ease;
}

.settings-sidebar .nav-link:hover {
    background: var(--bs-secondary-bg);
}

.settings-sidebar .nav-link.active {
    background: var(--bs-primary-bg-subtle);
    color: var(--bs-primary);
    border-left-color: var(--bs-primary);
    font-weight: 600;
}

@using sv_8d0ad8f6144142d78aa4d6bc1e17fbf2.Services

<div class="profile-section">
    <h4 class="mb-4">Profile Settings</h4>

    <div class="d-flex align-items-start gap-4 mb-4">
        <div class="avatar-preview text-center">
            <img src="@AvatarUrl" alt="Avatar" class="rounded-circle mb-2" width="100" height="100"
                 onerror="this.src='data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 width=%22100%22 height=%22100%22><rect fill=%22%23ccc%22 width=%22100%22 height=%22100%22/><text x=%2250%22 y=%2255%22 text-anchor=%22middle%22 fill=%22%23666%22 font-size=%2240%22>?</text></svg>'" />
            <div class="text-muted small text-break" style="max-width: 120px;">@AvatarUrl</div>
        </div>

        <div class="flex-grow-1">
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="DisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="Email" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Avatar URL</label>
                <input type="url" class="form-control" @bind="AvatarUrl" />
            </div>
        </div>
    </div>

    <div class="mb-4">
        <label class="form-label fw-semibold">Bio</label>
        <textarea class="form-control" rows="3" @bind="Bio"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(_message))
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string AvatarUrl = "";
    private string Bio = "";
    private string? _message;
    private bool _isError;
    private bool _saving;

    private UserProfile? _lastProfile;

    protected override void OnParametersSet()
    {
        if (Profile is not null && Profile != _lastProfile)
        {
            _lastProfile = Profile;
            LoadFromProfile(Profile);
        }
    }

    private void LoadFromProfile(UserProfile p)
    {
        DisplayName = p.DisplayName;
        Email = p.Email;
        AvatarUrl = p.AvatarUrl;
        Bio = p.Bio;
    }

    private async Task Save()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
            await OnSave.InvokeAsync(updated);
            _lastProfile = updated;
            _message = "Profile saved successfully!";
            _isError = false;
        }
        catch
        {
            _message = "Failed to save profile.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_lastProfile is not null)
        {
            LoadFromProfile(_lastProfile);
        }
        _message = null;
    }
}

@using sv_8d0ad8f6144142d78aa4d6bc1e17fbf2.Services

<div class="notifications-section">
    <h4 class="mb-4">Notification Preferences</h4>

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch" id="emailNotif"
                       checked="@EmailNotifications" @onchange="e => EmailNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="emailNotif">
                    <strong>Email Notifications</strong>
                    <div class="text-muted small">Receive notifications via email</div>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch" id="pushNotif"
                       checked="@PushNotifications" @onchange="e => PushNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="pushNotif">
                    <strong>Push Notifications</strong>
                    <div class="text-muted small">Receive push notifications in your browser</div>
                </label>
            </div>

            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" id="weeklyDigest"
                       checked="@WeeklyDigest" @onchange="e => WeeklyDigest = (bool)e.Value!" />
                <label class="form-check-label" for="weeklyDigest">
                    <strong>Weekly Digest</strong>
                    <div class="text-muted small">Receive a weekly summary email</div>
                </label>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">Muted Channels</h6>
            <p class="text-muted small">Select channels to mute. You won't receive notifications from muted channels.</p>

            @foreach (var channel in AvailableChannels)
            {
                var isMuted = MutedChannels.Contains(channel);
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="ch-@channel"
                           checked="@isMuted"
                           @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                    <label class="form-check-label" for="ch-@channel">@channel</label>
                </div>
            }
        </div>
    </div>

    @if (!string.IsNullOrEmpty(_message))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = [];
    private string? _message;
    private bool _saving;

    private static readonly string[] AvailableChannels =
        ["general", "announcements", "marketing", "engineering", "design", "support"];

    private NotificationPrefs? _lastPrefs;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && Prefs != _lastPrefs)
        {
            _lastPrefs = Prefs;
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = [.. Prefs.MutedChannels];
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task Save()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
            await OnSave.InvokeAsync(updated);
            _lastPrefs = updated;
            _message = "Notification preferences saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

.change-password-panel .card-header {
    cursor: pointer;
    user-select: none;
}

.change-password-panel .card-header:hover {
    background: var(--bs-secondary-bg);
}

.rotate-icon {
    display: inline-block;
    transform: rotate(90deg);
    transition: transform 0.2s ease;
}

@* Confirmation dialog before revoking a session *@

@if (Visible)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session?</p>
                    @if (!string.IsNullOrEmpty(DeviceName))
                    {
                        <p class="text-muted mb-0">
                            <strong>@DeviceName</strong> &mdash; @Location
                        </p>
                    }
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public string? DeviceName { get; set; }
    [Parameter] public string? Location { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@using sv_8d0ad8f6144142d78aa4d6bc1e17fbf2.Services

<div class="active-sessions">
    <h6 class="mb-3">Active Sessions</h6>

    @if (Sessions is null || Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover align-middle">
                <thead class="table-light">
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th class="text-end">Action</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        var isCurrent = session == Sessions.FirstOrDefault();
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="badge bg-success ms-1">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td class="text-end">
                                @if (!isCurrent)
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => RequestRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }

    <RevokeSessionDialog Visible="_showConfirm"
                         DeviceName="@_sessionToRevoke?.Device"
                         Location="@_sessionToRevoke?.Location"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
</div>

@code {
    [Parameter] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _showConfirm;

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showConfirm = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
        }
        _showConfirm = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showConfirm = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_8d0ad8f6144142d78aa4d6bc1e17fbf2.Services

<div class="security-section">
    <h4 class="mb-4">Security Settings</h4>

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="card my-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
                @if (LastPasswordChange.HasValue)
                {
                    <div class="text-muted small mt-1">
                        Last password change: @LastPasswordChange.Value.ToString("MMM dd, yyyy")
                    </div>
                }
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" id="twoFactor"
                       checked="@TwoFactorEnabled"
                       @onchange="e => OnTwoFactorToggle.InvokeAsync((bool)e.Value!)" />
            </div>
        </div>
    </div>

    <ActiveSessionsTable Sessions="Sessions" OnRevoke="OnRevokeSession" />
</div>

@code {
    [Parameter] public bool TwoFactorEnabled { get; set; }
    [Parameter] public DateTime? LastPasswordChange { get; set; }
    [Parameter] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<bool> OnTwoFactorToggle { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
}

@using sv_8d0ad8f6144142d78aa4d6bc1e17fbf2.Services

<div class="appearance-section">
    <h4 class="mb-4">Appearance Settings</h4>

    <div class="row">
        <div class="col-md-7">
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                                   value="@theme" checked="@(Theme == theme)"
                                   @onchange="() => Theme = theme" />
                            <label class="form-check-label" for="theme-@theme">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                                   value="@size" checked="@(FontSize == size)"
                                   @onchange="() => FontSize = size" />
                            <label class="form-check-label" for="fs-@size">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Language</h6>
                    <select class="form-select" @bind="Language">
                        @foreach (var lang in Languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-4">
