@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string AvatarUrl = "";
    private string Bio = "";
    private string? _message;
    private bool _isError;
    private bool _saving;

    private UserProfile? _lastProfile;

    protected override void OnParametersSet()
    {
        if (Profile is not null && Profile != _lastProfile)
        {
            _lastProfile = Profile;
            LoadFromProfile(Profile);
        }
    }

    private void LoadFromProfile(UserProfile p)
    {
        DisplayName = p.DisplayName;
        Email = p.Email;
        AvatarUrl = p.AvatarUrl;
        Bio = p.Bio;
    }

    private async Task Save()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
            await OnSave.InvokeAsync(updated);
            _lastProfile = updated;
            _message = "Profile saved successfully!";
            _isError = false;
        }
        catch
        {
            _message = "Failed to save profile.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_lastProfile is not null)
        {
            LoadFromProfile(_lastProfile);
        }
        _message = null;
    }
}
