    [Parameter] public bool TwoFactorEnabled { get; set; }
    [Parameter] public DateTime? LastPasswordChange { get; set; }
    [Parameter] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<bool> OnTwoFactorToggle { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
}

@using sv_8d0ad8f6144142d78aa4d6bc1e17fbf2.Services

<div class="appearance-section">
    <h4 class="mb-4">Appearance Settings</h4>

    <div class="row">
        <div class="col-md-7">
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                                   value="@theme" checked="@(Theme == theme)"
                                   @onchange="() => Theme = theme" />
                            <label class="form-check-label" for="theme-@theme">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                                   value="@size" checked="@(FontSize == size)"
                                   @onchange="() => FontSize = size" />
                            <label class="form-check-label" for="fs-@size">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Language</h6>
                    <select class="form-select" @bind="Language">
                        @foreach (var lang in Languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body d-flex justify-content-between align-items-center">
                    <div>
                        <h6 class="mb-0">Compact Mode</h6>
                        <small class="text-muted">Reduce spacing and padding throughout the UI</small>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" id="compactMode"
                               checked="@CompactMode" @onchange="e => CompactMode = (bool)e.Value!" />
                    </div>
                </div>
            </div>

            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert alert-success alert-dismissible fade show" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-5">
            <div class="card sticky-top" style="top: 1rem;">
                <div class="card-header">
                    <h6 class="mb-0">Live Preview</h6>
                </div>
                <div class="card-body preview-area @GetPreviewClasses()">
                    <h5 style="@GetFontStyle()">Dashboard</h5>
                    <p style="@GetFontStyle()">
                        This is a preview of how your content will look with the selected settings.
                    </p>
                    <div class="d-flex gap-2 mb-2" style="@GetSpacingStyle()">
                        <span class="badge bg-primary">Tag 1</span>
                        <span class="badge bg-secondary">Tag 2</span>
                        <span class="badge bg-info">Tag 3</span>
                    </div>
                    <button class="btn btn-sm btn-primary" style="@GetFontStyle()">Sample Button</button>
                    <div class="mt-2 small text-muted">
                        Theme: @Theme · Font: @FontSize · Language: @Language
                        @(CompactMode ? " · Compact" : "")
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "English";
    private bool CompactMode;
    private string? _message;
    private bool _saving;

    private static readonly string[] Languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese", "Korean"];

    private AppearanceSettings? _lastSettings;

    protected override void OnParametersSet()
    {
        if (Settings is not null && Settings != _lastSettings)
        {
            _lastSettings = Settings;
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = Theme switch
        {
            "Dark" => "bg-dark text-light",
            "System" => "bg-body-secondary",
            _ => "bg-light text-dark"
        };
        return classes;
    }

    private string GetFontStyle() => FontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    private string GetSpacingStyle() => CompactMode ? "gap: 0.25rem !important;" : "";

    private async Task Save()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
            await OnSave.InvokeAsync(updated);
            _lastSettings = updated;
            _message = "Appearance settings saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

